"use strict";const navToggler=document.querySelector(".nav__toggler"),navList=document.querySelector(".nav__list"),nav=document.querySelector(".nav"),header=document.querySelector(".header"),main=document.querySelector(".main");navToggler.addEventListener("click",(()=>{const e=navList.getBoundingClientRect().height,t=header.getBoundingClientRect().height,n=navToggler.querySelector(".fa-bars"),a=navToggler.querySelector(".fa-times");nav.classList.contains("nav-active")?(nav.classList.remove("nav-active"),main.style.transform="",navList.style.transform="translateY(-100%)",n.style.display="inline-block",a.style.display="none"):(nav.classList.add("nav-active"),main.style.transform=`translateY(${e-t}px)`,navList.style.transform="translateY(0)",n.style.display="none",a.style.display="inline-block")})),window.addEventListener("resize",(()=>{if(window.matchMedia("(max-width: 600px)").matches,nav.classList.contains("nav-active")){const e=navList.getBoundingClientRect().height,t=header.getBoundingClientRect().height;main.style.transform=`translateY(${e-t}px)`}})),main.addEventListener("transitionend",(function(){nav.classList.contains("nav-active")||(this.style.transform="")})),window.addEventListener("DOMContentLoaded",(e=>{const t=document.querySelectorAll(".projects__tile"),n=["--slideInLeft","--slideInRight","--slideInTop","--slideInBottom"];t.forEach((e=>{let t=Math.floor(Math.random()*n.length),a=n[t];e.classList.add("projects__tile"+a)}))}));